import{_ as e,o as a,c as i,ae as o}from"./chunks/framework.CB71nIlf.js";const u=JSON.parse('{"title":"Data Privacy Questions","description":"","frontmatter":{},"headers":[],"relativePath":"en/1-FAQ/4-data-privacy.md","filePath":"en/1-FAQ/4-data-privacy.md"}'),r={name:"en/1-FAQ/4-data-privacy.md"};function n(l,t,s,d,c,p){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="data-privacy-questions" tabindex="-1">Data Privacy Questions <a class="header-anchor" href="#data-privacy-questions" aria-label="Permalink to &quot;Data Privacy Questions&quot;">​</a></h1><h2 id="data-collection" tabindex="-1">Data Collection <a class="header-anchor" href="#data-collection" aria-label="Permalink to &quot;Data Collection&quot;">​</a></h2><h3 id="q1-what-data-does-the-platform-collect" tabindex="-1">Q1: What data does the platform collect? <a class="header-anchor" href="#q1-what-data-does-the-platform-collect" aria-label="Permalink to &quot;Q1: What data does the platform collect?&quot;">​</a></h3><p><strong>A</strong>: CogniAND platform collects the following types of data:</p><p><strong>Account Information:</strong></p><ul><li>Email address, name, gender, date of birth</li><li>User role (subject/experimenter)</li></ul><p><strong>Experiment Data:</strong></p><ul><li>Experiment response times, choice and judgment results</li><li>Task completion status, experiment progress records</li></ul><p><strong>Usage Data:</strong></p><ul><li>Login time and frequency, platform usage behavior</li><li>Experiment participation records, system interaction logs</li></ul><p>We follow the <strong>data minimization principle</strong>, collecting only necessary data and not collecting personal information unrelated to experiments.</p><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/1-data-collection.html">Data Collection</a></p><h3 id="q2-how-long-is-data-retained" tabindex="-1">Q2: How long is data retained? <a class="header-anchor" href="#q2-how-long-is-data-retained" aria-label="Permalink to &quot;Q2: How long is data retained?&quot;">​</a></h3><p><strong>A</strong>: Retention periods for different types of data:</p><table tabindex="0"><thead><tr><th>Data Type</th><th>Retention Period</th></tr></thead><tbody><tr><td>Account data</td><td>Duration of account existence</td></tr><tr><td>Experiment data</td><td>According to research requirements (typically 5-10 years)</td></tr><tr><td>Usage logs</td><td>6 months</td></tr><tr><td>Deleted account data</td><td>Permanently deleted within 30 days</td></tr></tbody></table><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/1-data-collection.html">Data Collection</a></p><h2 id="privacy-protection" tabindex="-1">Privacy Protection <a class="header-anchor" href="#privacy-protection" aria-label="Permalink to &quot;Privacy Protection&quot;">​</a></h2><h3 id="q3-how-does-the-platform-protect-my-privacy" tabindex="-1">Q3: How does the platform protect my privacy? <a class="header-anchor" href="#q3-how-does-the-platform-protect-my-privacy" aria-label="Permalink to &quot;Q3: How does the platform protect my privacy?&quot;">​</a></h3><p><strong>A</strong>: We employ multiple protection measures:</p><ol><li><p><strong>Data Anonymization</strong></p><ul><li>Experiment data identified by unique IDs</li><li>No linkage to personal identity information</li><li>Automatic anonymization on data export</li></ul></li><li><p><strong>Access Control</strong></p><ul><li>Strict permission management</li><li>Secure data storage</li><li>Limited data usage scope</li></ul></li><li><p><strong>User Control</strong></p><ul><li>Set privacy preferences</li><li>Control data sharing scope</li><li>Delete account at any time</li></ul></li></ol><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/2-privacy-protection.html">Privacy Protection</a></p><h3 id="q4-will-my-data-be-shared-with-third-parties" tabindex="-1">Q4: Will my data be shared with third parties? <a class="header-anchor" href="#q4-will-my-data-be-shared-with-third-parties" aria-label="Permalink to &quot;Q4: Will my data be shared with third parties?&quot;">​</a></h3><p><strong>A</strong>: We <strong>will not sell, rent, or trade</strong> your personal information. Data is only shared in the following situations:</p><ul><li>✅ With your explicit consent</li><li>✅ Required by laws and regulations</li><li>✅ Academic collaboration (anonymized data)</li><li>✅ Service providers (bound by confidentiality agreements)</li></ul><p>All third-party services we use (email services, cloud storage, analytics tools) have signed data protection agreements.</p><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/2-privacy-protection.html">Privacy Protection</a></p><h2 id="informed-consent" tabindex="-1">Informed Consent <a class="header-anchor" href="#informed-consent" aria-label="Permalink to &quot;Informed Consent&quot;">​</a></h2><h3 id="q5-what-is-informed-consent-why-is-it-important" tabindex="-1">Q5: What is informed consent? Why is it important? <a class="header-anchor" href="#q5-what-is-informed-consent-why-is-it-important" aria-label="Permalink to &quot;Q5: What is informed consent? Why is it important?&quot;">​</a></h3><p><strong>A</strong>: Informed consent is an important step before participating in experiments, ensuring you fully understand the experiment content and participate voluntarily.</p><p><strong>Informed consent includes:</strong></p><ul><li>Experiment information (purpose, process, duration, requirements)</li><li>Data usage (collection types, usage methods, retention period)</li><li>Participant rights (voluntary participation, withdrawal at any time, data access)</li><li>Risks and benefits (possible discomfort, potential benefits, compensation details)</li><li>Contact information (researchers, ethics committee, complaint channels)</li></ul><p><strong>Informed consent process:</strong></p><ol><li>Read the informed consent form</li><li>Liveness detection (verify real person)</li><li>Confirm consent</li><li>Start experiment</li></ol><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/3-informed-consent.html">Informed Consent</a></p><h3 id="q6-can-i-withdraw-consent-after-agreeing" tabindex="-1">Q6: Can I withdraw consent after agreeing? <a class="header-anchor" href="#q6-can-i-withdraw-consent-after-agreeing" aria-label="Permalink to &quot;Q6: Can I withdraw consent after agreeing?&quot;">​</a></h3><p><strong>A</strong>: Yes, you have the right to withdraw consent at any time:</p><ul><li>✅ Exit ongoing experiments</li><li>✅ Request deletion of collected data</li><li>⚠️ Does not affect completed experiment data (already used for research)</li></ul><p><strong>How to withdraw:</strong></p><ul><li>Click &quot;Exit Experiment&quot; in the experiment interface</li><li>Contact researchers or platform administrators</li><li>Submit a request through <a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a></li></ul><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/3-informed-consent.html">Informed Consent</a></p><h2 id="ethics-standards" tabindex="-1">Ethics Standards <a class="header-anchor" href="#ethics-standards" aria-label="Permalink to &quot;Ethics Standards&quot;">​</a></h2><h3 id="q7-what-ethical-principles-does-the-platform-follow" tabindex="-1">Q7: What ethical principles does the platform follow? <a class="header-anchor" href="#q7-what-ethical-principles-does-the-platform-follow" aria-label="Permalink to &quot;Q7: What ethical principles does the platform follow?&quot;">​</a></h3><p><strong>A</strong>: CogniAND platform strictly adheres to psychological research ethics standards:</p><p><strong>Four core principles:</strong></p><ol><li><p><strong>Respect Principle</strong></p><ul><li>Respect participants&#39; autonomy and privacy</li><li>Respect cultural differences, treat all participants equally</li></ul></li><li><p><strong>Beneficence Principle</strong></p><ul><li>Maximize research benefits, minimize potential risks</li><li>Provide necessary support, share research results</li></ul></li><li><p><strong>Justice Principle</strong></p><ul><li>Fair selection of participants, reasonable distribution of research burdens and benefits</li><li>Avoid discrimination and bias, protect vulnerable groups&#39; rights</li></ul></li><li><p><strong>Integrity Principle</strong></p><ul><li>Truthfully report research results, avoid academic misconduct</li><li>Maintain research transparency, use data responsibly</li></ul></li></ol><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/4-ethics.html">Ethics Standards</a></p><h3 id="q8-how-are-experiments-ethically-reviewed" tabindex="-1">Q8: How are experiments ethically reviewed? <a class="header-anchor" href="#q8-how-are-experiments-ethically-reviewed" aria-label="Permalink to &quot;Q8: How are experiments ethically reviewed?&quot;">​</a></h3><p><strong>A</strong>: All experiments must undergo ethical review:</p><p><strong>Review process:</strong></p><ol><li>Researchers submit experiment protocol</li><li>Ethics committee reviews</li><li>Assess risks and benefits</li><li>Provide modification suggestions</li><li>Approve or reject</li></ol><p><strong>Review criteria:</strong></p><ul><li>Scientific validity of research design</li><li>Adequacy of informed consent</li><li>Reasonableness of risk assessment</li><li>Effectiveness of privacy protection</li><li>Standardization of data management</li></ul><p><strong>Special group protection:</strong></p><ul><li>Minors require guardian consent</li><li>Vulnerable groups require special ethical review and enhanced protection measures</li></ul><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/4-ethics.html">Ethics Standards</a></p><h2 id="user-rights" tabindex="-1">User Rights <a class="header-anchor" href="#user-rights" aria-label="Permalink to &quot;User Rights&quot;">​</a></h2><h3 id="q9-what-data-rights-do-i-have" tabindex="-1">Q9: What data rights do I have? <a class="header-anchor" href="#q9-what-data-rights-do-i-have" aria-label="Permalink to &quot;Q9: What data rights do I have?&quot;">​</a></h3><p><strong>A</strong>: You have the following data rights:</p><table tabindex="0"><thead><tr><th>Right</th><th>Description</th></tr></thead><tbody><tr><td>✅ Data access right</td><td>View your own data</td></tr><tr><td>✅ Data modification right</td><td>Modify personal information</td></tr><tr><td>✅ Data deletion right</td><td>Request account deletion</td></tr><tr><td>✅ Data export right</td><td>Export your own data</td></tr><tr><td>✅ Right to refuse</td><td>Refuse specific data collection</td></tr><tr><td>✅ Right to withdraw</td><td>Withdraw informed consent</td></tr></tbody></table><p><strong>How to exercise rights:</strong></p><ul><li>Log in to personal center to view and modify data</li><li>Contact <a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a> to request deletion or export</li><li>Withdraw consent in the experiment interface</li></ul><p>Details: <a href="/cogniand-manual.github.io/en/5-data-privacy/">Data &amp; Privacy</a></p><h3 id="q10-how-do-i-delete-my-data" tabindex="-1">Q10: How do I delete my data? <a class="header-anchor" href="#q10-how-do-i-delete-my-data" aria-label="Permalink to &quot;Q10: How do I delete my data?&quot;">​</a></h3><p><strong>A</strong>: You can delete data through the following methods:</p><p><strong>Delete account:</strong></p><ol><li>Contact platform administrator to request account deletion</li><li>Provide account information for identity verification</li><li>Confirm deletion operation (irreversible)</li><li>All personal data permanently deleted within 30 days</li></ol><p><strong>Delete experiment data:</strong></p><ul><li>Can exit at any time during experiments and request data deletion</li><li>Completed experiment data may be retained for research purposes (anonymized)</li></ul><p><strong>Important notes:</strong></p><ul><li>⚠️ Deletion operation is irreversible, please proceed with caution</li><li>⚠️ Anonymized data already used for scientific research may not be deletable</li><li>⚠️ Account cannot be recovered after deletion</li></ul><p>Contact: <a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a></p><hr><p><strong>Need more detailed information?</strong> Please see:</p><ul><li><a href="/cogniand-manual.github.io/en/5-data-privacy/">Data &amp; Privacy Complete Documentation</a></li><li><a href="/cogniand-manual.github.io/en/5-data-privacy/1-data-collection.html">Data Collection</a></li><li><a href="/cogniand-manual.github.io/en/5-data-privacy/2-privacy-protection.html">Privacy Protection</a></li><li><a href="/cogniand-manual.github.io/en/5-data-privacy/3-informed-consent.html">Informed Consent</a></li><li><a href="/cogniand-manual.github.io/en/5-data-privacy/4-ethics.html">Ethics Standards</a></li><li><a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a></li></ul>',74)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
